queries.sphinxql:
create table t (title text, vec float_vector knn_type='hnsw' knn_dims='4' hnsw_similarity='L2');
insert into t (id,title,vec) values (1,'machine learning basics',(0.10,0.10,0.10,0.10));
insert into t (id,title,vec) values (2,'deep learning for machine vision',(0.15,0.12,0.08,0.11));
insert into t (id,title,vec) values (3,'machine learning algorithms',(0.20,0.15,0.12,0.09));
insert into t (id,title,vec) values (4,'cooking recipes italian',(0.11,0.09,0.13,0.10));
insert into t (id,title,vec) values (5,'travel guide europe',(0.18,0.11,0.10,0.12));
insert into t (id,title,vec) values (6,'machine learning in production',(5.00,5.00,5.00,5.00));
flush ramchunk t;

select id, hybrid_score() from t where match('machine learning') and knn(vec, 5, (0.1, 0.1, 0.1, 0.1)) order by hybrid_score() desc, id asc option fusion_method='rrf';

select id, hybrid_score() from t where match('machine learning') and knn(vec, 5, (0.1, 0.1, 0.1, 0.1)) order by hybrid_score() desc, id asc limit 2 option fusion_method='rrf';
